        )
        .build()
).onSuccess {
    // activación correcta
}.onError { error ->
    // gestionar el error
}

// O al identificar usuarios
Adapty.identify(
    customerUserId = "YOUR_USER_ID",
    androidObfuscatedAccountId = "YOUR_OBFUSCATED_ACCOUNT_ID"
).onSuccess {
    // identificación correcta
}.onError { error ->
    // gestionar el error
}
```
